require("fs"),async function(){console.log("Fetching products from Firestore...");try{const e=await fetch("https://firestore.googleapis.com/v1/projects/speed-catalogue/databases/(default)/documents/artifacts/speed-catalogue/public/data/products?pageSize=1000");if(!(await e.json()).documents)return void console.error("No products found");console.log("Warming up main home page...");try{await fetch("https://speedgifts.net/"),console.log("Main page warmed up successfully.")}catch(e){console.error("Failed to warm up main page:",e)}console.log("Warming up shop page...");try{await fetch("https://speedgifts.net/shop"),console.log("Shop page warmed up successfully.")}catch(e){console.error("Failed to warm up shop page:",e)}console.log("Fetching categories from Firestore...");try{const e=await fetch("https://firestore.googleapis.com/v1/projects/speed-catalogue/databases/(default)/documents/artifacts/speed-catalogue/public/data/categories?pageSize=100"),o=await e.json();if(o.documents){const e=o.documents.map(e=>e.name.split("/").pop());console.log(`Fetched ${e.length} categories to warm up.`);let t=0,a=0;for(let o=0;o<e.length;o+=BATCH_SIZE){const s=e.slice(o,o+BATCH_SIZE).map(async e=>{const o=`https://speedgifts.net/shop?c=${encodeURIComponent(e)}`;try{(await fetch(o)).ok?t++:a++}catch(e){a++}});await Promise.all(s),await new Promise(e=>setTimeout(e,500)),console.log(`Category Progress: ${Math.min(o+BATCH_SIZE,e.length)} / ${e.length}`)}console.log(`Category Cache warming complete. Success: ${t}, Failed: ${a}`)}}catch(e){console.error("Failed to warm up categories:",e)}console.log(`Manual Cache warming complete. Success: ${successCount}, Failed: ${failCount}`)}catch(e){console.error("Error:",e)}}();